VALUES
  ('dietitian-moex-08234', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關蛋白質之胺基酸組成的說明，何者較為正確？', '["大分子量的蛋白質比小分子量的蛋白質更容易含有20種胺基酸", "功能不同的蛋白質，它們的胺基酸組成通常有明顯差異", "分子量相同的蛋白質，它們的胺基酸組成通常也相同", "蛋白質的功能決定於分子中雙硫鍵的數量與位置"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08235', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '細胞膜內含有下列何種多元不飽和脂肪酸（polyunsaturated fatty acid）？', '["油酸（oleic acid）", "乳酸（lactic acid）", "唾液酸（sialic acid）", "花生四烯酸（arachidonic acid）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08236', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關人類可以使用三酸甘油酯（triacylglycerol）經糖質新生路徑（gluconeogenic pathway）而產生淨葡萄 糖（net glucose production）之敘述，下列解釋何者正確？', '["三酸甘油酯之甘油可以轉變成糖質新生的中間物，並用於合成葡萄糖", "三酸甘油酯之脂肪酸經降解後產生的乙醯輔酶A（acetyl CoA）是糖質新生的原料", "三酸甘油酯之脂肪酸經降解後產生的乙醯輔酶A（acetyl CoA），可進入TCA cycle，其中間產物是糖 質新生的原料", "三酸甘油酯之脂肪酸經降解後產生的乙醯輔酶A（acetyl CoA），可進入乙醛酸循環（glyoxylate cycle）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08237', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '自VLDL中釋出脂肪酸時，需要下列何種細胞外酵素參與作用？', '["激素敏感性脂解酶（hormone-sensitive lipase）", "脂蛋白脂解酶（lipoprotein lipase）", "肝臟三酸甘油酯脂解酶（hepatic triacylglycerol lipase）", "雙酸甘油酯脂解酶（diacylglycerol lipase）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08238', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '當水分子與下列何種化合物混合時，經攪動之後可形成微胞（micelle）？', '["絲胺酸（serine）", "甘油（glycerol）", "磷脂（phospholipid）", "三酸甘油酯（triglyceride）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08239', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在糖解作用（glycolysis）生成 ATP 的反應中，反應物為下列那一個組合？①glyceraldehyde-3-phosphate', '["1,3-bisphosphoglycerate", "3-phosphoglycerate", "phosphoenolpyruvate", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08240', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在豆莢和麥麩等食物因含有特定大量寡醣類，不能被酵素分解，僅被腸內菌代謝利用，這些醣類是：', '["melezitose", "amygdalin", "laetrile", "stachyose"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
