  ('dietitian-moex-08242', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '以Haworth系統分析果糖（fructose）形成環狀結構時，第幾個碳的氫氧基（hydroxyl group）會與第2個 碳形成呋喃糖（furanose）結構？', '["第3個", "第4個", "第5個", "第6個"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08243', 'dietitian', 'dietitian-moex-099-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試社會工作師考試試題 類       科：營養師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "9084df7a62cd", "answer_pdf_sha1": "89e048286306", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 99, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
